import { boolean, integer, jsonb, numeric, pgTable, text, timestamp, uuid, varchar } from "drizzle-orm/pg-core";
export const taxJurisdictionsTable = pgTable("tax_jurisdictions", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id"),
    jurisdictionCode: varchar("jurisdiction_code", { length: 80 }).notNull(),
    jurisdictionName: varchar("jurisdiction_name", { length: 160 }).notNull(),
    countryCode: varchar("country_code", { length: 2 }),
    stateCode: varchar("state_code", { length: 80 }),
    regionCode: varchar("region_code", { length: 80 }),
    parentJurisdictionId: uuid("parent_jurisdiction_id"),
    isActive: boolean("is_active").notNull(),
    metadata: jsonb("metadata").notNull(),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
});
export const taxRulesTable = pgTable("tax_rules", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id"),
    organizationId: uuid("organization_id"),
    ruleCode: varchar("rule_code", { length: 80 }).notNull(),
    ruleName: varchar("rule_name", { length: 160 }).notNull(),
    description: text("description"),
    taxType: varchar("tax_type", { length: 40 }).notNull(),
    calculationMethod: varchar("calculation_method", { length: 40 }).notNull(),
    compoundingMode: varchar("compounding_mode", { length: 40 }).notNull(),
    ratePercent: numeric("rate_percent"),
    fixedAmount: numeric("fixed_amount"),
    currencyCode: varchar("currency_code", { length: 3 }).notNull(),
    jurisdictionId: uuid("jurisdiction_id"),
    jurisdictionCode: varchar("jurisdiction_code", { length: 80 }).notNull(),
    taxCategory: varchar("tax_category", { length: 80 }).notNull(),
    taxGroupCode: varchar("tax_group_code", { length: 80 }),
    priority: integer("priority").notNull(),
    scopeLevel: varchar("scope_level", { length: 40 }).notNull(),
    appliesTo: varchar("applies_to", { length: 80 }).notNull(),
    isRecoverable: boolean("is_recoverable").notNull(),
    requiresApproval: boolean("requires_approval").notNull(),
    approvalStatus: varchar("approval_status", { length: 40 }).notNull(),
    version: integer("version").notNull(),
    parentRuleId: uuid("parent_rule_id"),
    effectiveFrom: timestamp("effective_from").notNull(),
    effectiveTo: timestamp("effective_to"),
    status: varchar("status", { length: 40 }).notNull(),
    metadata: jsonb("metadata").notNull(),
    createdBy: uuid("created_by"),
    updatedBy: uuid("updated_by"),
    deactivatedAt: timestamp("deactivated_at"),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
});
export const taxProfilesTable = pgTable("tax_profiles", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id").notNull(),
    organizationId: uuid("organization_id"),
    ownerType: varchar("owner_type", { length: 40 }).notNull(),
    ownerId: uuid("owner_id").notNull(),
    taxRegistrationNumber: varchar("tax_registration_number", { length: 120 }),
    gstNumber: varchar("gst_number", { length: 120 }),
    vatNumber: varchar("vat_number", { length: 120 }),
    taxIdentifier: varchar("tax_identifier", { length: 120 }),
    businessTaxCategory: varchar("business_tax_category", { length: 80 }),
    taxCategory: varchar("tax_category", { length: 80 }).notNull(),
    exemptionStatus: varchar("exemption_status", { length: 40 }).notNull(),
    exemptionReason: text("exemption_reason"),
    jurisdictionCode: varchar("jurisdiction_code", { length: 80 }).notNull(),
    registrationDetails: jsonb("registration_details").notNull(),
    metadata: jsonb("metadata").notNull(),
    version: integer("version").notNull(),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
});
export const taxCalculationSnapshotsTable = pgTable("tax_calculation_snapshots", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id").notNull(),
    organizationId: uuid("organization_id"),
    sourceModule: varchar("source_module", { length: 80 }).notNull(),
    sourceEntityType: varchar("source_entity_type", { length: 80 }),
    sourceEntityId: varchar("source_entity_id", { length: 120 }),
    calculationHash: varchar("calculation_hash", { length: 128 }).notNull(),
    currencyCode: varchar("currency_code", { length: 3 }).notNull(),
    taxableAmount: numeric("taxable_amount").notNull(),
    taxAmount: numeric("tax_amount").notNull(),
    totalAmount: numeric("total_amount").notNull(),
    jurisdictionCode: varchar("jurisdiction_code", { length: 80 }).notNull(),
    ruleVersionSnapshot: jsonb("rule_version_snapshot").notNull(),
    breakdown: jsonb("breakdown").notNull(),
    inputSnapshot: jsonb("input_snapshot").notNull(),
    effectiveDate: timestamp("effective_date").notNull(),
    calculatedBy: uuid("calculated_by"),
    createdAt: timestamp("created_at").notNull(),
});
